contracts/EpicMintMarketplace.sol.content:
// SPDX-License-Identifier: GPL-3.0

pragma solidity >=0.8.2 <0.9.0;

import "@openzeppelin/contracts/token/ERC721/IERC721.sol";
import "@openzeppelin/contracts/security/ReentrancyGuard.sol";
import "@openzeppelin/contracts/access/Ownable.sol";
import "@openzeppelin/contracts/security/Pausable.sol";

/**
 * @title EpicMintMarketplace
 * @dev Decentralized marketplace for NFT trading
 * Features: Auctions, Fixed price sales, Offers, Royalties
 */
contract EpicMintMarketplace is ReentrancyGuard, Ownable, Pausable {

    // Platform fee (in basis points, 250 = 2.5%)
    uint256 public platformFeePercent = 250;

    // Marketplace listing
    struct Listing {
        uint256 tokenId;
        address nftContract;
        address payable seller;
        uint256 price;
        uint256 listingTime;
        bool active;
    }

    // Auction structure
    struct Auction {
        uint256 tokenId;
        address nftContract;
        address payable seller;
        uint256 startingPrice;
        uint256 currentBid;
        address payable currentBidder;
        uint256 startTime;
        uint256 endTime;
        bool active;
        bool ended;
    }

    // Offer structure
    struct Offer {
        uint256 tokenId;
        address nftContract;
        address payable offerer;
        uint256 amount;
        uint256 expiration;
        bool active;
    }

    // Mappings
    mapping(bytes32 => Listing) public listings;
    mapping(bytes32 => Auction) public auctions;
    mapping(bytes32 => Offer[]) public offers;
    mapping(address => uint256) public pendingWithdrawals;

    // Events
    event ItemListed(
        bytes32 indexed listingId,
        uint256 indexed tokenId,
        address indexed nftContract,
        address seller,
        uint256 price
    );

    event ItemSold(
        bytes32 indexed listingId,
        uint256 indexed tokenId,
        address indexed nftContract,
        address seller,
        address buyer,
        uint256 price
    );

    event AuctionCreated(
        bytes32 indexed auctionId,
        uint256 indexed tokenId,
        address indexed nftContract,
        address seller,
        uint256 startingPrice,
        uint256 duration
    );

    event BidPlaced(
        bytes32 indexed auctionId,
        address indexed bidder,
        uint256 amount
    );

    event AuctionEnded(
        bytes32 indexed auctionId,
        address indexed winner,
        uint256 winningBid
    );

    event OfferMade(
        bytes32 indexed offerId,
        uint256 indexed tokenId,
        address indexed nftContract,
        address offerer,
        uint256 amount
    );

    event OfferAccepted(
        bytes32 indexed offerId,
        uint256 indexed tokenId,
        address indexed nftContract,
        address seller,
        address buyer,
        uint256 amount
    );

    /**
     * @dev Create a fixed price listing
     */
    function createListing(
        uint256 tokenId,
        address nftContract,
        uint256 price
    ) external whenNotPaused returns (bytes32) {
        require(price > 0, "Price must be greater than 0");
        require(IERC721(nftContract).ownerOf(tokenId) == msg.sender, "Not token owner");
        require(IERC721(nftContract).isApprovedForAll(msg.sender, address(this)) || 
                IERC721(nftContract).getApproved(tokenId) == address(this), "Marketplace not approved");

        bytes32 listingId = keccak256(abi.encodePacked(nftContract, tokenId, msg.sender, block.timestamp));

        listings[listingId] = Listing({
            tokenId: tokenId,
            nftContract: nftContract,
            seller: payable(msg.sender),
            price: price,
            listingTime: block.timestamp,
            active: true
        });

        emit ItemListed(listingId, tokenId, nftContract, msg.sender, price);
        return listingId;
    }

    /**
     * @dev Buy item from fixed price listing
     */
    function buyItem(bytes32 listingId) external payable nonReentrant whenNotPaused {
        Listing storage listing = listings[listingId];
        require(listing.active, "Listing not active");
        require(msg.value >= listing.price, "Insufficient payment");
        require(IERC721(listing.nftContract).ownerOf(listing.tokenId) == listing.seller, "Seller no longer owns token");

        listing.active = false;

        // Calculate fees
        uint256 platformFee = (listing.price * platformFeePercent) / 10000;
        uint256 sellerAmount = listing.price - platformFee;

        // Transfer NFT
        IERC721(listing.nftContract).safeTransferFrom(listing.seller, msg.sender, listing.tokenId);

        // Transfer payments
        if (platformFee > 0) {
            payable(owner()).transfer(platformFee);
        }
        listing.seller.transfer(sellerAmount);

        // Refund excess payment
        if (msg.value > listing.price) {
            payable(msg.sender).transfer(msg.value - listing.price);
        }

        emit ItemSold(listingId, listing.tokenId, listing.nftContract, listing.seller, msg.sender, listing.price);
    }

    /**
     * @dev Cancel a listing
     */
    function cancelListing(bytes32 listingId) external {
        Listing storage listing = listings[listingId];
        require(listing.active, "Listing not active");
        require(listing.seller == msg.sender, "Not the seller");

        listing.active = false;
    }

    /**
     * @dev Create an auction
     */
    function createAuction(
        uint256 tokenId,
        address nftContract,
        uint256 startingPrice,
        uint256 duration
    ) external whenNotPaused returns (bytes32) {
        require(startingPrice > 0, "Starting price must be greater than 0");
        require(duration >= 3600, "Auction duration must be at least 1 hour");
        require(duration <= 7 days, "Auction duration cannot exceed 7 days");
        require(IERC721(nftContract).ownerOf(tokenId) == msg.sender, "Not token owner");
        require(IERC721(nftContract).isApprovedForAll(msg.sender, address(this)) || 
                IERC721(nftContract).getApproved(tokenId) == address(this), "Marketplace not approved");

        bytes32 auctionId = keccak256(abi.encodePacked(nftContract, tokenId, msg.sender, block.timestamp));

        auctions[auctionId] = Auction({
            tokenId: tokenId,
            nftContract: nftContract,
            seller: payable(msg.sender),
            startingPrice: startingPrice,
            currentBid: 0,
            currentBidder: payable(address(0)),
            startTime: block.timestamp,
            endTime: block.timestamp + duration,
            active: true,
            ended: false
        });

        emit AuctionCreated(auctionId, tokenId, nftContract, msg.sender, startingPrice, duration);
        return auctionId;
    }

    /**
     * @dev Place a bid on an auction
     */
    function placeBid(bytes32 auctionId) external payable nonReentrant whenNotPaused {
        Auction storage auction = auctions[auctionId];
        require(auction.active, "Auction not active");
        require(block.timestamp < auction.endTime, "Auction has ended");
        require(msg.sender != auction.seller, "Seller cannot bid");

        uint256 minBid = auction.currentBid > 0 ? auction.currentBid + ((auction.currentBid * 5) / 100) : auction.startingPrice;
        require(msg.value >= minBid, "Bid too low");

        // Return previous bid
        if (auction.currentBidder != address(0)) {
            pendingWithdrawals[auction.currentBidder] += auction.currentBid;
        }

        auction.currentBid = msg.value;
        auction.currentBidder = payable(msg.sender);

        // Extend auction if bid placed in last 15 minutes
        if (auction.endTime - block.timestamp < 900) {
            auction.endTime = block.timestamp + 900;
        }

        emit BidPlaced(auctionId, msg.sender, msg.value);
    }

    /**
     * @dev End an auction
     */
    function endAuction(bytes32 auctionId) external nonReentrant {
        Auction storage auction = auctions[auctionId];
        require(auction.active, "Auction not active");
        require(block.timestamp >= auction.endTime, "Auction still ongoing");
        require(!auction.ended, "Auction already ended");

        auction.active = false;
        auction.ended = true;

        if (auction.currentBidder != address(0)) {
            // Transfer NFT to winner
            IERC721(auction.nftContract).safeTransferFrom(
                auction.seller, 
                auction.currentBidder, 
                auction.tokenId
            );

            // Calculate and transfer payments
            uint256 platformFee = (auction.currentBid * platformFeePercent) / 10000;
            uint256 sellerAmount = auction.currentBid - platformFee;

            if (platformFee > 0) {
                payable(owner()).transfer(platformFee);
            }
            auction.seller.transfer(sellerAmount);

            emit AuctionEnded(auctionId, auction.currentBidder, auction.currentBid);
        } else {
            emit AuctionEnded(auctionId, address(0), 0);
        }
    }

    /**
     * @dev Make an offer on an NFT
     */
    function makeOffer(
        uint256 tokenId,
        address nftContract,
        uint256 expiration
    ) external payable whenNotPaused returns (bytes32) {
        require(msg.value > 0, "Offer must be greater than 0");
        require(expiration > block.timestamp, "Expiration must be in the future");
        require(expiration <= block.timestamp + 30 days, "Expiration too far in future");

        bytes32 offerId = keccak256(abi.encodePacked(nftContract, tokenId, msg.sender, block.timestamp));

        offers[offerId].push(Offer({
            tokenId: tokenId,
            nftContract: nftContract,
            offerer: payable(msg.sender),
            amount: msg.value,
            expiration: expiration,
            active: true
        }));

        emit OfferMade(offerId, tokenId, nftContract, msg.sender, msg.value);
        return offerId;
    }

    /**
     * @dev Accept an offer
     */
    function acceptOffer(bytes32 offerId, uint256 offerIndex) external nonReentrant whenNotPaused {
        Offer storage offer = offers[offerId][offerIndex];
        require(offer.active, "Offer not active");
        require(block.timestamp <= offer.expiration, "Offer has expired");
        require(IERC721(offer.nftContract).ownerOf(offer.tokenId) == msg.sender, "Not token owner");
        require(IERC721(offer.nftContract).isApprovedForAll(msg.sender, address(this)) || 
                IERC721(offer.nftContract).getApproved(offer.tokenId) == address(this), "Marketplace not approved");

        offer.active = false;

        // Transfer NFT
        IERC721(offer.nftContract).safeTransferFrom(msg.sender, offer.offerer, offer.tokenId);

        // Calculate and transfer payments
        uint256 platformFee = (offer.amount * platformFeePercent) / 10000;
        uint256 sellerAmount = offer.amount - platformFee;

        if (platformFee > 0) {
            payable(owner()).transfer(platformFee);
        }
        payable(msg.sender).transfer(sellerAmount);

        emit OfferAccepted(offerId, offer.tokenId, offer.nftContract, msg.sender, offer.offerer, offer.amount);
    }

    /**
     * @dev Withdraw pending payments
     */
    function withdraw() external nonReentrant {
        uint256 amount = pendingWithdrawals[msg.sender];
        require(amount > 0, "No funds to withdraw");

        pendingWithdrawals[msg.sender] = 0;
        payable(msg.sender).transfer(amount);
    }

    /**
     * @dev Get listing details
     */
    function getListing(bytes32 listingId) external view returns (Listing memory) {
        return listings[listingId];
    }

    /**
     * @dev Get auction details
     */
    function getAuction(bytes32 auctionId) external view returns (Auction memory) {
        return auctions[auctionId];
    }

    /**
     * @dev Get offers for a specific NFT
     */
    function getOffers(bytes32 offerId) external view returns (Offer[] memory) {
        return offers[offerId];
    }

    /**
     * @dev Update platform fee (only owner)
     */
    function updatePlatformFee(uint256 newFeePercent) external onlyOwner {
        require(newFeePercent <= 1000, "Fee cannot exceed 10%");
        platformFeePercent = newFeePercent;
    }

    /**
     * @dev Pause the marketplace
     */
    function pause() external onlyOwner {
        _pause();
    }

    /**
     * @dev Unpause the marketplace
     */
    function unpause() external onlyOwner {
        _unpause();
    }

    /**
     * @dev Emergency withdraw (only owner)
     */
    function emergencyWithdraw() external onlyOwner {
        payable(owner()).transfer(address(this).balance);
    }
}

contracts/EpicMintNFT.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.19;

import "@openzeppelin/contracts/token/ERC721/ERC721.sol";
import "@openzeppelin/contracts/token/ERC721/extensions/ERC721URIStorage.sol";
import "@openzeppelin/contracts/token/ERC721/extensions/ERC721Burnable.sol";
import "@openzeppelin/contracts/access/Ownable.sol";
import "@openzeppelin/contracts/utils/Counters.sol";
import "@openzeppelin/contracts/security/ReentrancyGuard.sol";
import "@openzeppelin/contracts/security/Pausable.sol";

/**
 * @title EpicMintNFT
 * @dev NFT Contract for Stories, Comics, and Poems
 * Features: Minting, Marketplace, Royalties, Batch Operations
 */
contract EpicMintNFT is ERC721, ERC721URIStorage, ERC721Burnable, Ownable, ReentrancyGuard, Pausable {
    using Counters for Counters.Counter;

    Counters.Counter private _tokenIdCounter;

    // Contract metadata
    string private _contractURI;

    // Marketplace functionality
    struct MarketItem {
        uint256 tokenId;
        address payable seller;
        address payable owner;
        uint256 price;
        bool sold;
        uint256 listedAt;
    }

    mapping(uint256 => MarketItem) private marketItems;
    mapping(uint256 => bool) private itemsForSale;

    // Royalty functionality (EIP-2981)
    struct RoyaltyInfo {
        address recipient;
        uint256 percentage; // Basis points (100 = 1%)
    }

    mapping(uint256 => RoyaltyInfo) private _tokenRoyalty;
    uint256 private _defaultRoyaltyPercentage = 250; // 2.5%

    // Events
    event NFTMinted(uint256 indexed tokenId, address indexed to, string tokenURI);
    event NFTListed(uint256 indexed tokenId, uint256 price, address indexed seller);
    event NFTSold(uint256 indexed tokenId, uint256 price, address indexed seller, address indexed buyer);
    event NFTUnlisted(uint256 indexed tokenId, address indexed seller);
    event RoyaltySet(uint256 indexed tokenId, address indexed recipient, uint256 percentage);

    // Modifiers
    modifier tokenExists(uint256 tokenId) {
        require(_exists(tokenId), "EpicMintNFT: Token does not exist");
        _;
    }

    modifier onlyTokenOwner(uint256 tokenId) {
        require(ownerOf(tokenId) == msg.sender, "EpicMintNFT: Not token owner");
        _;
    }

    constructor(string memory name, string memory symbol) ERC721(name, symbol) {
        _tokenIdCounter.increment(); // Start from token ID 1
    }

    /**
     * @dev Mint a new NFT
     * @param to Address to mint the NFT to
     * @param tokenURI Metadata URI for the NFT
     * @param royaltyRecipient Address to receive royalties
     * @param royaltyPercentage Royalty percentage in basis points
     */
    function mintNFT(
        address to,
        string memory tokenURI,
        address royaltyRecipient,
        uint256 royaltyPercentage
    ) public whenNotPaused returns (uint256) {
        require(to != address(0), "EpicMintNFT: Cannot mint to zero address");
        require(bytes(tokenURI).length > 0, "EpicMintNFT: Token URI cannot be empty");
        require(royaltyPercentage <= 1000, "EpicMintNFT: Royalty percentage too high"); // Max 10%

        uint256 tokenId = _tokenIdCounter.current();
        _tokenIdCounter.increment();

        _safeMint(to, tokenId);
        _setTokenURI(tokenId, tokenURI);

        // Set royalty info
        if (royaltyRecipient != address(0)) {
            _setTokenRoyalty(tokenId, royaltyRecipient, royaltyPercentage);
        }

        emit NFTMinted(tokenId, to, tokenURI);
        return tokenId;
    }

    /**
     * @dev Batch mint multiple NFTs
     */
    function batchMintNFT(
        address[] memory recipients,
        string[] memory tokenURIs,
        address[] memory royaltyRecipients,
        uint256[] memory royaltyPercentages
    ) external whenNotPaused returns (uint256[] memory) {
        require(recipients.length == tokenURIs.length, "EpicMintNFT: Arrays length mismatch");
        require(recipients.length == royaltyRecipients.length, "EpicMintNFT: Arrays length mismatch");
        require(recipients.length == royaltyPercentages.length, "EpicMintNFT: Arrays length mismatch");
        require(recipients.length <= 100, "EpicMintNFT: Too many tokens to mint");

        uint256[] memory tokenIds = new uint256[](recipients.length);

        for (uint256 i = 0; i < recipients.length; i++) {
            tokenIds[i] = mintNFT(
                recipients[i],
                tokenURIs[i],
                royaltyRecipients[i],
                royaltyPercentages[i]
            );
        }

        return tokenIds;
    }

    /**
     * @dev List NFT for sale
     */
    function listNFT(uint256 tokenId, uint256 price) 
        external 
        tokenExists(tokenId) 
        onlyTokenOwner(tokenId) 
        whenNotPaused 
    {
        require(price > 0, "EpicMintNFT: Price must be greater than 0");
        require(!itemsForSale[tokenId], "EpicMintNFT: Token already listed");

        // Transfer token to contract for escrow
        _transfer(msg.sender, address(this), tokenId);

        marketItems[tokenId] = MarketItem({
            tokenId: tokenId,
            seller: payable(msg.sender),
            owner: payable(address(this)),
            price: price,
            sold: false,
            listedAt: block.timestamp
        });

        itemsForSale[tokenId] = true;

        emit NFTListed(tokenId, price, msg.sender);
    }

    /**
     * @dev Buy NFT from marketplace
     */
    function buyNFT(uint256 tokenId) 
        external 
        payable 
        tokenExists(tokenId) 
        nonReentrant 
        whenNotPaused 
    {
        require(itemsForSale[tokenId], "EpicMintNFT: Token not for sale");

        MarketItem storage item = marketItems[tokenId];
        require(!item.sold, "EpicMintNFT: Token already sold");
        require(msg.value >= item.price, "EpicMintNFT: Insufficient payment");

        // Calculate royalty
        (address royaltyRecipient, uint256 royaltyAmount) = royaltyInfo(tokenId, item.price);

        // Calculate platform fee (2.5%)
        uint256 platformFee = (item.price * 250) / 10000;
        uint256 sellerAmount = item.price - royaltyAmount - platformFee;

        // Mark as sold
        item.sold = true;
        itemsForSale[tokenId] = false;

        // Transfer NFT to buyer
        _transfer(address(this), msg.sender, tokenId);

        // Transfer payments
        if (royaltyAmount > 0 && royaltyRecipient != address(0)) {
            payable(royaltyRecipient).transfer(royaltyAmount);
        }

        if (platformFee > 0) {
            payable(owner()).transfer(platformFee);
        }

        item.seller.transfer(sellerAmount);

        // Refund excess payment
        if (msg.value > item.price) {
            payable(msg.sender).transfer(msg.value - item.price);
        }

        emit NFTSold(tokenId, item.price, item.seller, msg.sender);
    }

    /**
     * @dev Unlist NFT from marketplace
     */
    function unlistNFT(uint256 tokenId) 
        external 
        tokenExists(tokenId) 
        whenNotPaused 
    {
        require(itemsForSale[tokenId], "EpicMintNFT: Token not listed");

        MarketItem storage item = marketItems[tokenId];
        require(item.seller == msg.sender, "EpicMintNFT: Not the seller");
        require(!item.sold, "EpicMintNFT: Token already sold");

        // Return NFT to seller
        _transfer(address(this), msg.sender, tokenId);

        // Remove from marketplace
        itemsForSale[tokenId] = false;
        delete marketItems[tokenId];

        emit NFTUnlisted(tokenId, msg.sender);
    }

    /**
     * @dev Set royalty information for a token
     */
    function _setTokenRoyalty(uint256 tokenId, address recipient, uint256 percentage) internal {
        require(recipient != address(0), "EpicMintNFT: Invalid royalty recipient");
        require(percentage <= 1000, "EpicMintNFT: Royalty percentage too high");

        _tokenRoyalty[tokenId] = RoyaltyInfo(recipient, percentage);
        emit RoyaltySet(tokenId, recipient, percentage);
    }

    /**
     * @dev Get royalty information (EIP-2981)
     */
    function royaltyInfo(uint256 tokenId, uint256 salePrice) 
        public 
        view 
        returns (address, uint256) 
    {
        RoyaltyInfo memory royalty = _tokenRoyalty[tokenId];

        if (royalty.recipient == address(0)) {
            return (address(0), 0);
        }

        uint256 royaltyAmount = (salePrice * royalty.percentage) / 10000;
        return (royalty.recipient, royaltyAmount);
    }

    /**
     * @dev Get market item details
     */
    function getMarketItem(uint256 tokenId) 
        external 
        view 
        returns (MarketItem memory) 
    {
        return marketItems[tokenId];
    }

    /**
     * @dev Check if token is for sale
     */
    function isTokenForSale(uint256 tokenId) external view returns (bool) {
        return itemsForSale[tokenId];
    }

    /**
     * @dev Get all tokens for sale
     */
    function getTokensForSale() external view returns (uint256[] memory) {
        uint256 totalTokens = _tokenIdCounter.current() - 1;
        uint256 forSaleCount = 0;

        // Count tokens for sale
        for (uint256 i = 1; i <= totalTokens; i++) {
            if (itemsForSale[i] && !marketItems[i].sold) {
                forSaleCount++;
            }
        }

        // Create array of tokens for sale
        uint256[] memory tokensForSale = new uint256[](forSaleCount);
        uint256 index = 0;

        for (uint256 i = 1; i <= totalTokens; i++) {
            if (itemsForSale[i] && !marketItems[i].sold) {
                tokensForSale[index] = i;
                index++;
            }
        }

        return tokensForSale;
    }

    /**
     * @dev Get tokens owned by an address
     */
    function getTokensByOwner(address owner) external view returns (uint256[] memory) {
        uint256 totalTokens = _tokenIdCounter.current() - 1;
        uint256 ownedCount = 0;

        // Count owned tokens
        for (uint256 i = 1; i <= totalTokens; i++) {
            if (_exists(i) && ownerOf(i) == owner) {
                ownedCount++;
            }
        }

        // Create array of owned tokens
        uint256[] memory ownedTokens = new uint256[](ownedCount);
        uint256 index = 0;

        for (uint256 i = 1; i <= totalTokens; i++) {
            if (_exists(i) && ownerOf(i) == owner) {
                ownedTokens[index] = i;
                index++;
            }
        }

        return ownedTokens;
    }

    /**
     * @dev Get current token ID
     */
    function getCurrentTokenId() external view returns (uint256) {
        return _tokenIdCounter.current() - 1;
    }

    /**
     * @dev Set contract URI
     */
    function setContractURI(string memory contractURI_) external onlyOwner {
        _contractURI = contractURI_;
    }

    /**
     * @dev Get contract URI
     */
    function contractURI() external view returns (string memory) {
        return _contractURI;
    }

    /**
     * @dev Pause the contract
     */
    function pause() external onlyOwner {
        _pause();
    }

    /**
     * @dev Unpause the contract
     */
    function unpause() external onlyOwner {
        _unpause();
    }

    /**
     * @dev Withdraw contract balance
     */
    function withdraw() external onlyOwner {
        uint256 balance = address(this).balance;
        require(balance > 0, "EpicMintNFT: No funds to withdraw");
        payable(owner()).transfer(balance);
    }

    // Required overrides
    function _burn(uint256 tokenId) internal override(ERC721, ERC721URIStorage) {
        super._burn(tokenId);

        // Clear marketplace listing
        if (itemsForSale[tokenId]) {
            itemsForSale[tokenId] = false;
            delete marketItems[tokenId];
        }

        // Clear royalty info
        delete _tokenRoyalty[tokenId];
    }

    function tokenURI(uint256 tokenId)
        public
        view
        override(ERC721, ERC721URIStorage)
        returns (string memory)
    {
        return super.tokenURI(tokenId);
    }

    function supportsInterface(bytes4 interfaceId)
        public
        view
        override(ERC721, ERC721URIStorage)
        returns (bool)
    {
        return super.supportsInterface(interfaceId);
    }
}

